{
  "name": "StoreWeb Clone",
  "description": "A fully functional e-commerce clone with customer and seller dashboards, review systems (text/photo/video), and AI-powered product assistance.",
  "requestFramePermissions": [
    "microphone",
    "camera"
  ]
}

import React, { useEffect, useRef, useState } from 'react';
import { Camera, X, RotateCcw, Maximize, Settings2 } from 'lucide-react';

interface Props {
  productImage: string;
  category: string;
  onClose: () => void;
}

const VirtualTryOn: React.FC<Props> = ({ productImage, category, onClose }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const [stream, setStream] = useState<MediaStream | null>(null);
  const [scale, setScale] = useState(1);
  const [yOffset, setYOffset] = useState(0);
  const [xOffset, setXOffset] = useState(0);
  const [isReady, setIsReady] = useState(false);

  const isEyewear = category.toLowerCase().includes('eyewear') || category.toLowerCase().includes('glasses') || category.toLowerCase().includes('goggles');
  const isWatch = category.toLowerCase().includes('watch');

  useEffect(() => {
    const startCamera = async () => {
      try {
        const mediaStream = await navigator.mediaDevices.getUserMedia({ 
          video: { facingMode: 'user', width: { ideal: 1280 }, height: { ideal: 720 } } 
        });
        setStream(mediaStream);
        if (videoRef.current) {
          videoRef.current.srcObject = mediaStream;
          videoRef.current.onloadedmetadata = () => setIsReady(true);
        }
      } catch (err) {
        console.error("Camera error:", err);
        alert("Unable to access camera. Please check permissions.");
        onClose();
      }
    };

    startCamera();

    return () => {
      if (stream) {
        stream.getTracks().forEach(track => track.stop());
      }
    };
  }, []);

  // Simple auto-centering for eyewear (simulating face tracking)
  useEffect(() => {
    if (isEyewear && isReady) {
      // Small delay to simulate initial "scan"
      const timeout = setTimeout(() => {
        setYOffset(-15); // Adjust for typical face position in selfie view
      }, 1000);
      return () => clearTimeout(timeout);
    }
  }, [isEyewear, isReady]);

  return (
    <div className="fixed inset-0 z-[100] bg-black flex flex-col items-center justify-center p-4">
      <div className="relative w-full max-w-4xl aspect-video bg-gray-900 rounded-2xl overflow-hidden shadow-2xl border-4 border-storeweb-primary/30">

        {/* Video Feed */}
        <video 
          ref={videoRef} 
          autoPlay 
          playsInline 
          className="w-full h-full object-cover scale-x-[-1]"
        />

        {/* Scanning Overlay Effect */}
        <div className="absolute inset-0 pointer-events-none border-[1px] border-storeweb-primary/20 bg-gradient-to-b from-storeweb-primary/5 to-transparent">
           <div className="w-full h-[2px] bg-storeweb-primary/50 absolute top-0 animate-[scan_3s_linear_infinite]" />
        </div>

        {/* Product Overlay */}
        {isReady && (
          <div 
            className="absolute inset-0 flex items-center justify-center pointer-events-none"
            style={{ 
              transform: `translate(${xOffset}px, ${yOffset}px) scale(${scale})` 
            }}
          >
            <div className="relative">
              <img 
                src={productImage} 
                className={`max-w-[150px] sm:max-w-[200px] transition-all duration-300 drop-shadow-2xl mix-blend-multiply ${isEyewear ? 'opacity-90' : 'opacity-100'}`}
                style={{
                   filter: isEyewear ? 'brightness(1.1) contrast(1.1)' : 'none'
                }}
                alt="AR Overlay"
              />
              {/* AR Guide Lines */}
              {isWatch && (
                <div className="absolute inset-0 -m-4 border-2 border-dashed border-storeweb-primary/40 rounded-lg animate-pulse" />
              )}
            </div>
          </div>
        )}

        {/* UI Controls Header */}
        <div className="absolute top-0 inset-x-0 p-4 flex justify-between items-center bg-gradient-to-b from-black/60 to-transparent">
          <div className="flex items-center gap-3">
             <div className="bg-storeweb-primary p-2 rounded-full animate-pulse">
                <Camera size={20} className="text-white" />
             </div>
             <div>
                <h3 className="text-white font-bold text-sm">Virtual Mirror</h3>
                <p className="text-xs text-sky-200">AR {isEyewear ? 'Face' : 'Wrist'} Mode Active</p>
             </div>
          </div>
          <button onClick={onClose} className="bg-white/10 hover:bg-white/20 p-2 rounded-full text-white backdrop-blur-md transition-all">
             <X size={24} />
          </button>
        </div>

        {/* Instructions Overlay */}
        {!isReady && (
          <div className="absolute inset-0 flex flex-center bg-black/50 backdrop-blur-sm flex flex-col items-center justify-center text-white p-8 text-center">
             <div className="w-12 h-12 border-4 border-sky-500 border-t-transparent rounded-full animate-spin mb-4" />
             <h2 className="text-xl font-bold">Initializing AR...</h2>
             <p className="text-sm text-gray-300 mt-2">Position your {isEyewear ? 'face' : 'wrist'} in front of the camera.</p>
          </div>
        )}

        {/* Positioning UI Controls (Bottom Sidebar) */}
        <div className="absolute bottom-6 left-6 right-6 flex flex-col sm:flex-row items-center justify-between gap-4">
           <div className="flex bg-black/60 backdrop-blur-md rounded-2xl p-4 border border-white/10 gap-6 w-full sm:w-auto">
              <div className="flex-1 flex flex-col gap-1">
                 <label className="text-[10px] uppercase font-bold text-gray-400">Scale</label>
                 <input 
                    type="range" min="0.5" max="2" step="0.1" value={scale} 
                    onChange={(e) => setScale(parseFloat(e.target.value))}
                    className="w-32 accent-storeweb-primary" 
                 />
              </div>
              <div className="flex-1 flex flex-col gap-1">
                 <label className="text-[10px] uppercase font-bold text-gray-400">Position Y</label>
                 <input 
                    type="range" min="-100" max="100" step="1" value={yOffset} 
                    onChange={(e) => setYOffset(parseFloat(e.target.value))}
                    className="w-32 accent-storeweb-primary" 
                 />
              </div>
              <button 
                onClick={() => { setScale(1); setYOffset(isEyewear ? -15 : 0); setXOffset(0); }}
                className="bg-white/10 hover:bg-white/20 p-2 rounded-lg text-white"
                title="Reset"
              >
                <RotateCcw size={18} />
              </button>
           </div>

           <div className="bg-storeweb-dark/80 text-white px-4 py-2 rounded-full border border-storeweb-primary/30 flex items-center gap-2 text-xs backdrop-blur-md shadow-lg">
              <Settings2 size={14} className="text-sky-400" />
              <span>Align your {isEyewear ? 'eyes with the bridge' : 'wrist within the box'}</span>
           </div>
        </div>
      </div>

      <style>{`
        @keyframes scan {
          0% { top: 0%; opacity: 0.2; }
          50% { opacity: 1; }
          100% { top: 100%; opacity: 0.2; }
        }
      `}</style>
    </div>
  );
};

export default VirtualTryOn;

import React, { useState, useEffect } from 'react';
import { useParams } from 'react-router-dom';
import { useStore } from '../context/StoreContext';
import { Star, Truck, ShieldCheck, MapPin, Video, Image as ImageIcon, Send, Camera } from 'lucide-react';
import { Review, OrderStatus } from '../types';
import { getProductAnalysis, summarizeReviews } from '../services/geminiService';
import ImageMagnifier from '../components/ImageMagnifier';
import VirtualTryOn from '../components/VirtualTryOn';

const ProductDetails: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const { products, addToCart, reviews, user, addReview } = useStore();
  const [activeImage, setActiveImage] = useState<string>('');
  const [aiResponse, setAiResponse] = useState<string>('');
  const [userQuery, setUserQuery] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [summary, setSummary] = useState<string | null>(null);
  const [showAR, setShowAR] = useState(false);

  // New Review Form State
  const [reviewForm, setReviewForm] = useState<{rating: number, title: string, text: string}>({
    rating: 5, title: '', text: ''
  });

  const product = products.find(p => p.id === id) || products[0]; 
  const productReviews = reviews[product.id] || [];

  useEffect(() => {
    if (product) setActiveImage(product.image);
  }, [product]);

  if (!product) return <div>Product not found</div>;

  const handleAiQuery = async () => {
    if (!userQuery.trim()) return;
    setIsTyping(true);
    const answer = await getProductAnalysis(product, userQuery);
    setAiResponse(answer);
    setIsTyping(false);
  };

  const handleReviewSummary = async () => {
    setIsTyping(true);
    const reviewTexts = productReviews.map(r => r.text);
    const sum = await summarizeReviews(reviewTexts);
    setSummary(sum);
    setIsTyping(false);
  };

  const submitReview = () => {
    if(!user) return alert("Please sign in to review");
    const newReview: Review = {
      id: Math.random().toString(),
      userId: user.id,
      userName: user.name,
      date: new Date().toLocaleDateString(),
      verifiedPurchase: true,
      ...reviewForm
    };
    addReview(product.id, newReview);
    setReviewForm({ rating: 5, title: '', text: '' });
  };

  const canTryOn = product.category.toLowerCase().includes('watch') || 
                   product.category.toLowerCase().includes('eyewear') || 
                   product.category.toLowerCase().includes('glasses');

  return (
    <div className="max-w-screen-xl mx-auto p-4 bg-white mt-4">
      {showAR && (
        <VirtualTryOn 
          productImage={product.image} 
          category={product.category} 
          onClose={() => setShowAR(false)} 
        />
      )}

      <div className="grid grid-cols-1 md:grid-cols-12 gap-8">
        {/* Images */}
        <div className="md:col-span-4 lg:col-span-5 flex gap-4 sticky top-24 self-start z-30">
           <div className="flex flex-col gap-2">
              <img src={product.image} className="w-10 h-10 border hover:border-storeweb-primary cursor-pointer object-contain" onMouseEnter={() => setActiveImage(product.image)} />
              {product.images?.map((img, idx) => (
                <img key={idx} src={img} className="w-10 h-10 border hover:border-storeweb-primary cursor-pointer object-contain" onMouseEnter={() => setActiveImage(img)} />
              ))}

              {/* Virtual Try-On Thumbnail Button */}
              {canTryOn && (
                <button 
                  onClick={() => setShowAR(true)}
                  className="w-10 h-10 border border-sky-200 bg-sky-50 hover:bg-sky-100 flex items-center justify-center text-sky-600 rounded cursor-pointer group"
                  title="Try it on virtually"
                >
                  <Camera size={18} className="group-hover:scale-110 transition-transform" />
                </button>
              )}
           </div>
           <div className="flex-1 relative">
             <ImageMagnifier src={activeImage} />

             {/* Main Try-On Overlay Action */}
             {canTryOn && (
               <button 
                 onClick={() => setShowAR(true)}
                 className="absolute bottom-4 left-4 right-4 bg-black/60 hover:bg-black/80 text-white backdrop-blur-md px-4 py-2 rounded-full flex items-center justify-center gap-2 text-xs font-bold transition-all shadow-lg z-10 border border-white/20"
               >
                 <Camera size={16} />
                 VIRTUAL TRY-ON (LIVE MIRROR)
               </button>
             )}
           </div>
        </div>

        {/* Details */}
        <div className="md:col-span-5 lg:col-span-4">
           <h1 className="text-2xl font-medium text-gray-900">{product.title}</h1>
           <div className="flex items-center gap-2 mt-1">
              <div className="flex text-yellow-400">
                {[...Array(5)].map((_, i) => <Star key={i} size={16} fill="currentColor" />)}
              </div>
              <span className="text-storeweb-accent text-sm hover:underline">{product.reviewCount} ratings</span>
           </div>
           <div className="border-t border-b border-gray-200 py-4 my-4">
              <div className="flex items-start gap-1">
                 <span className="text-xs pt-1">₹</span>
                 <span className="text-3xl font-medium">{Math.floor(product.price)}</span>
                 <span className="text-xs pt-1">{(product.price % 1).toFixed(2).substring(1)}</span>
              </div>
              <p className="text-sm text-gray-500 mt-2">Inclusive of all taxes</p>
           </div>
           <div className="mt-4">
              <h3 className="font-bold mb-2">About this item</h3>
              <p className="text-sm text-gray-700 leading-relaxed">{product.description}</p>
           </div>

           {/* AI Assistant */}
           <div className="mt-8 p-4 bg-slate-50 rounded-lg border border-slate-200">
             <h3 className="font-bold text-sm text-slate-800 flex items-center gap-2 mb-2">
               <span className="bg-storeweb-dark text-white text-xs px-1 rounded">AI</span>
               Ask about this product
             </h3>
             <div className="flex gap-2 mb-2">
               <input 
                 type="text" 
                 value={userQuery}
                 onChange={(e) => setUserQuery(e.target.value)}
                 placeholder="Is this good for gaming?"
                 className="flex-1 border border-slate-300 rounded px-2 py-1 text-sm focus:outline-none focus:ring-1 focus:ring-storeweb-primary"
               />
               <button onClick={handleAiQuery} className="bg-storeweb-primary text-white p-1 rounded hover:bg-storeweb-hover transition-colors">
                 <Send size={16} />
               </button>
             </div>
             {isTyping && <p className="text-xs text-gray-500 animate-pulse">AI is thinking...</p>}
             {aiResponse && <p className="text-sm text-gray-800 bg-white p-2 rounded border border-slate-200 mt-2 shadow-sm">{aiResponse}</p>}
           </div>
        </div>

        {/* Buy Box */}
        <div className="md:col-span-3 lg:col-span-3">
          <div className="border border-gray-300 rounded-lg p-4 sticky top-24">
             <div className="text-2xl font-medium text-red-700 mb-2">₹{product.price.toFixed(2)}</div>
             <div className="text-sm text-gray-600 mb-4">
                FREE delivery <b>Monday, Nov 15</b>.
                <div className="flex items-center gap-1 text-xs mt-1 text-storeweb-accent">
                   <MapPin size={12} /> Deliver to New York 10001
                </div>
             </div>
             <h4 className="text-green-700 text-lg font-medium mb-4">In Stock</h4>

             <button 
               onClick={() => addToCart(product, 1)}
               className="w-full bg-storeweb-primary hover:bg-storeweb-hover text-white rounded-full py-2 text-sm mb-2 shadow-sm transition-colors font-medium"
             >
               Add to Cart
             </button>
             <button className="w-full bg-orange-500 hover:bg-orange-600 text-white rounded-full py-2 text-sm mb-4 shadow-sm transition-colors font-medium">
               Buy Now
             </button>

             <div className="text-xs text-gray-500 grid grid-cols-2 gap-y-1">
                <span>Ships from</span> <span>StoreWeb</span>
                <span>Sold by</span> <span>StoreWeb Services</span>
             </div>
          </div>
        </div>
      </div>

      {/* Reviews Section */}
      <div className="mt-12 border-t pt-8">
         <h2 className="text-2xl font-bold mb-6">Customer Reviews</h2>

         <div className="flex flex-col md:flex-row gap-8">
           <div className="w-full md:w-1/3">
             <div className="flex items-center gap-2 mb-4">
               <span className="text-4xl font-bold">{product.rating}</span>
               <div className="flex flex-col">
                 <div className="flex text-yellow-400">
                    {[...Array(5)].map((_, i) => <Star key={i} size={20} fill="currentColor" />)}
                 </div>
                 <span className="text-sm text-gray-500">{product.reviewCount} global ratings</span>
               </div>
             </div>
             <button 
               onClick={handleReviewSummary}
               className="text-sm border border-gray-300 shadow-sm rounded-md px-4 py-2 hover:bg-gray-50 w-full mb-4 text-left flex justify-between items-center"
             >
               <span>Summarize reviews with AI</span>
               <span className="text-xs bg-gradient-to-r from-sky-500 to-indigo-500 text-white px-1 rounded">Beta</span>
             </button>
             {summary && (
               <div className="bg-gray-50 p-3 rounded text-sm text-gray-800 mb-4 border border-gray-200">
                 <h4 className="font-bold mb-1">AI Summary:</h4>
                 <div className="whitespace-pre-wrap">{summary}</div>
               </div>
             )}

             {/* Add Review */}
             <div className="border p-4 rounded bg-gray-50 mt-4">
               <h3 className="font-bold text-sm mb-2">Write a review</h3>
               <input className="w-full border p-2 mb-2 text-sm rounded" placeholder="Title" value={reviewForm.title} onChange={e => setReviewForm({...reviewForm, title: e.target.value})}/>
               <textarea className="w-full border p-2 mb-2 text-sm rounded" placeholder="Review text" value={reviewForm.text} onChange={e => setReviewForm({...reviewForm, text: e.target.value})} />
               <button onClick={submitReview} className="w-full border border-gray-300 bg-white hover:bg-gray-100 py-1 text-sm rounded shadow-sm transition-colors">Submit Review</button>
             </div>
           </div>

           <div className="w-full md:w-2/3 space-y-6">
             {productReviews.map((review) => (
               <div key={review.id} className="border-b pb-6">
                 <div className="flex items-center gap-2 mb-1">
                   <div className="w-8 h-8 rounded-full bg-slate-200 flex items-center justify-center text-xs text-slate-700 font-bold">{review.userName[0]}</div>
                   <span className="text-sm font-medium">{review.userName}</span>
                 </div>
                 <div className="flex items-center gap-2 mb-2">
                   <div className="flex text-yellow-400">
                      {[...Array(5)].map((_, i) => <Star key={i} size={14} fill={i < review.rating ? "currentColor" : "none"} className={i >= review.rating ? "text-gray-300" : ""} />)}
                   </div>
                   <span className="font-bold text-sm">{review.title}</span>
                 </div>
                 <div className="text-xs text-gray-500 mb-2">Reviewed on {review.date}</div>
                 {review.verifiedPurchase && (
                   <div className="text-xs text-storeweb-primary font-bold mb-2">Verified Purchase</div>
                 )}
                 <p className="text-sm text-gray-800 mb-3">{review.text}</p>

                 {/* Media */}
                 <div className="flex gap-2">
                   {review.images?.map((img, i) => (
                     <img key={i} src={img} className="w-20 h-20 object-cover border rounded cursor-pointer" />
                   ))}
                   {review.video && (
                      <div className="relative w-32 h-20 bg-black rounded overflow-hidden group cursor-pointer">
                        <video src={review.video} className="w-full h-full object-cover" />
                        <div className="absolute inset-0 flex items-center justify-center bg-black/30 group-hover:bg-black/10">
                           <Video className="text-white" />
                        </div>
                      </div>
                   )}
                 </div>
               </div>
             ))}
           </div>
         </div>
      </div>
    </div>
  );
};

export default ProductDetails;

import { GoogleGenAI, Chat } from "@google/genai";
import { Product } from "../types";

// Always use the named parameter and obtain API key directly from process.env.API_KEY
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const getProductAnalysis = async (product: Product, query: string): Promise<string> => {
  try {
    // Using gemini-3-flash-preview for basic text tasks as per guidelines
    const model = 'gemini-3-flash-preview';
    const response = await ai.models.generateContent({
      model: model,
      contents: `User Question: ${query}`,
      config: {
        systemInstruction: `
          You are an expert StoreWeb product assistant. 
          Product Details:
          Title: ${product.title}
          Description: ${product.description}
          Price: ₹${product.price}
          Category: ${product.category}

          Answer the user's question concisely based on the product details provided. If the answer isn't in the details, make a reasonable inference or state you don't know, but remain helpful and sales-oriented.
        `,
      },
    });

    // Use .text property to get the string content
    return response.text || "I couldn't generate a response at this time.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "Sorry, I'm having trouble connecting to the AI assistant right now.";
  }
};

export const summarizeReviews = async (reviews: string[]): Promise<string> => {
  try {
     const model = 'gemini-3-flash-preview';
     const response = await ai.models.generateContent({
       model: model,
       contents: `Summarize these reviews:\n${reviews.join('\n---\n')}`,
       config: {
         systemInstruction: "Please provide a concise summary of the pros and cons based on these reviews. Bullet points are preferred.",
       },
     });

     return response.text || "Could not summarize reviews.";
  } catch (error) {
    return "Unavailable to summarize at this moment.";
  }
}

export const createChatSession = (contextData: string): Chat => {
  // Use gemini-3-flash-preview for general support tasks
  return ai.chats.create({
    model: 'gemini-3-flash-preview',
    config: {
      systemInstruction: `
        You are StoreWeb's advanced AI customer support agent.
        You are helpful, polite, concise, and professional.

        You have access to the following context data in JSON format:
        ${contextData}

        YOUR RESPONSIBILITIES:
        1. Answer questions about products in the catalog (price, features, etc.). Prices are in Rupees (₹).
        2. Check order status for the user based on the 'recentOrders' list.
        3. Assist with cart contents.
        4. If a user asks about an order ID that exists in 'recentOrders', provide its status and details.
        5. If the user asks "Where is my order?", ask them for the Order ID or list their recent orders if available.
        6. If a user asks about reviews for a specific product, look up the 'productReviews' using the product's ID (which you can find by matching the product name in 'productCatalog'). Summarize the customer sentiment, ratings, and pros/cons based on those reviews.

        Keep answers short and easy to read.
      `,
    },
  });
};

import React, { useState, useRef, useEffect } from 'react';
import { MessageCircle, X, Send, Minimize2, Bot, User } from 'lucide-react';
import { useStore } from '../context/StoreContext';
import { createChatSession } from '../services/geminiService';
import { Chat } from '@google/genai';

interface Message {
  role: 'user' | 'model';
  text: string;
}

const Chatbot: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState<Message[]>([
    { role: 'model', text: 'Hi! I\'m StoreWeb\'s AI assistant. How can I help you today?' }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);

  // Dragging State
  const [position, setPosition] = useState<{x: number, y: number} | null>(null);
  const [isDragging, setIsDragging] = useState(false);
  const dragOffset = useRef({ x: 0, y: 0 });

  const { user, cart, orders, products, reviews } = useStore();
  const chatSessionRef = useRef<Chat | null>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const windowRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, isOpen]);

  // Initialize position on open
  useEffect(() => {
    if (isOpen && position === null) {
      // Default to bottom-right, above the button
      const width = window.innerWidth < 640 ? 320 : 384; // w-80 (320px) vs w-96 (384px)
      const height = 500;
      setPosition({
        x: Math.max(10, window.innerWidth - width - 24),
        y: Math.max(10, window.innerHeight - height - 100)
      });
    }
  }, [isOpen]);

  // Initialize chat session when opened or when context changes significantly
  useEffect(() => {
    if (isOpen) {
      const contextData = JSON.stringify({
        currentUser: user ? { name: user.name, email: user.email, role: user.role } : 'Guest',
        cartItems: cart.map(c => ({ title: c.title, qty: c.quantity, price: c.price })),
        recentOrders: orders.filter(o => o.userId === user?.id).map(o => ({
          id: o.id,
          status: o.status,
          total: o.total,
          date: o.date,
          items: o.items.map(i => i.title)
        })),
        productCatalog: products.map(p => ({
           id: p.id,
           title: p.title,
           price: p.price,
           category: p.category,
           description: p.description
        })),
        productReviews: reviews
      });

      chatSessionRef.current = createChatSession(contextData);
    }
  }, [isOpen, user, cart, orders, products, reviews]);

  // Drag Handlers
  const handleMouseDown = (e: React.MouseEvent) => {
    if (windowRef.current) {
      setIsDragging(true);
      const rect = windowRef.current.getBoundingClientRect();
      dragOffset.current = {
        x: e.clientX - rect.left,
        y: e.clientY - rect.top
      };
    }
  };

  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      if (isDragging) {
        e.preventDefault();
        setPosition({
          x: e.clientX - dragOffset.current.x,
          y: e.clientY - dragOffset.current.y
        });
      }
    };

    const handleMouseUp = () => {
      setIsDragging(false);
    };

    if (isDragging) {
      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);
    }

    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [isDragging]);

  const handleSend = async () => {
    if (!input.trim()) return;

    const userMsg = input;
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setIsLoading(true);

    try {
      if (!chatSessionRef.current) {
         // Fallback re-init if something went wrong
         const contextData = JSON.stringify({
          currentUser: user ? { name: user.name, email: user.email, role: user.role } : 'Guest',
          cartItems: cart.map(c => ({ title: c.title, qty: c.quantity, price: c.price })),
          recentOrders: orders.filter(o => o.userId === user?.id).map(o => ({
            id: o.id,
            status: o.status,
            total: o.total,
            date: o.date,
            items: o.items.map(i => i.title)
          })),
          productCatalog: products.map(p => ({
             id: p.id,
             title: p.title,
             price: p.price,
             category: p.category,
             description: p.description
          })),
          productReviews: reviews
         }); 
         chatSessionRef.current = createChatSession(contextData);
      }

      // result.text is a property, not a method
      const result = await chatSessionRef.current.sendMessage({ message: userMsg });
      setMessages(prev => [...prev, { role: 'model', text: result.text || "I'm not sure how to answer that." }]);
    } catch (error) {
      console.error(error);
      setMessages(prev => [...prev, { role: 'model', text: "Sorry, I'm having trouble connecting right now." }]);
    } finally {
      setIsLoading(false);
    }
  };

  const handleKeyPress = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter') handleSend();
  };

  return (
    <>
      {isOpen && position && (
        <div 
          ref={windowRef}
          style={{ left: position.x, top: position.y }}
          className="fixed z-[60] bg-white rounded-lg shadow-2xl w-80 sm:w-96 h-[500px] flex flex-col border border-gray-200 overflow-hidden animate-in fade-in zoom-in-95 duration-200"
        >
          {/* Header - Draggable */}
          <div 
            onMouseDown={handleMouseDown}
            className="bg-storeweb-light text-white p-4 flex justify-between items-center shadow-md cursor-move select-none"
          >
             <div className="flex items-center gap-2 pointer-events-none">
                <div className="bg-white text-storeweb-light p-1 rounded-full">
                   <Bot size={20} />
                </div>
                <div>
                   <h3 className="font-bold text-sm">StoreWeb Assistant</h3>
                   <span className="text-xs text-green-400 flex items-center gap-1">
                     <span className="w-1.5 h-1.5 bg-green-400 rounded-full"></span> Online
                   </span>
                </div>
             </div>
             <button onClick={() => setIsOpen(false)} className="hover:bg-white/10 p-1 rounded cursor-pointer">
                <Minimize2 size={18} />
             </button>
          </div>

          {/* Messages */}
          <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-gray-50">
             {messages.map((msg, idx) => (
               <div key={idx} className={`flex gap-2 ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                  {msg.role === 'model' && (
                    <div className="w-8 h-8 rounded-full bg-storeweb-light text-white flex items-center justify-center shrink-0 mt-1">
                      <Bot size={14} />
                    </div>
                  )}
                  <div className={`max-w-[80%] p-3 rounded-lg text-sm shadow-sm ${
                    msg.role === 'user' 
                      ? 'bg-storeweb-accent text-white rounded-tr-none' 
                      : 'bg-white text-gray-800 border border-gray-200 rounded-tl-none'
                  }`}>
                     {msg.text}
                  </div>
                  {msg.role === 'user' && (
                    <div className="w-8 h-8 rounded-full bg-gray-200 text-gray-600 flex items-center justify-center shrink-0 mt-1">
                      <User size={14} />
                    </div>
                  )}
               </div>
             ))}
             {isLoading && (
               <div className="flex gap-2 justify-start">
                  <div className="w-8 h-8 rounded-full bg-storeweb-light text-white flex items-center justify-center shrink-0">
                      <Bot size={14} />
                  </div>
                  <div className="bg-white border border-gray-200 p-3 rounded-lg rounded-tl-none shadow-sm">
                     <div className="flex gap-1">
                        <span className="w-2 h-2 bg-gray-400 rounded-full animate-bounce"></span>
                        <span className="w-2 h-2 bg-gray-400 rounded-full animate-bounce delay-100"></span>
                        <span className="w-2 h-2 bg-gray-400 rounded-full animate-bounce delay-200"></span>
                     </div>
                  </div>
               </div>
             )}
             <div ref={messagesEndRef} />
          </div>

          {/* Input */}
          <div className="p-3 bg-white border-t border-gray-200">
             <div className="flex items-center gap-2 bg-gray-100 rounded-full px-4 py-2 border focus-within:border-storeweb-primary focus-within:ring-1 focus-within:ring-storeweb-primary transition-all">
