// Extend Window interface for the experimental FaceDetector API
declare global {
  interface Window {
    FaceDetector: any;
  }
}

const VirtualTryOn: React.FC<Props> = ({ productImage, category, onClose }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [stream, setStream] = useState<MediaStream | null>(null);
  const [isReady, setIsReady] = useState(false);
  const [faceData, setFaceData] = useState({ x: 0, y: 0, width: 0, height: 0, angle: 0 });
  const [manualScale, setManualScale] = useState(1);
  const [isTracking, setIsTracking] = useState(false);

  const isEyewear = category.toLowerCase().includes('eyewear') || category.toLowerCase().includes('glasses') || category.toLowerCase().includes('goggles');
  const isWatch = category.toLowerCase().includes('watch');

  // Stop camera function
  const stopCamera = () => {
    if (stream) {
      stream.getTracks().forEach(track => {
        track.stop();
        console.log("Camera track stopped:", track.label);
      });
      setStream(null);
    }
  };

  const handleClose = () => {
    stopCamera();
    onClose();
  };

  useEffect(() => {
    const startCamera = async () => {
      try {
        const mediaStream = await navigator.mediaDevices.getUserMedia({ 
          video: { facingMode: 'user', width: { ideal: 1280 }, height: { ideal: 720 } } 
        });
        setStream(mediaStream);
        if (videoRef.current) {
          videoRef.current.srcObject = mediaStream;
          videoRef.current.onloadedmetadata = () => {
            setIsReady(true);
            setIsTracking(true);
          };
        }
      } catch (err) {
        console.error("Camera error:", err);
        alert("Unable to access camera. Please check permissions.");
        handleClose();
      }
    };

    startCamera();

    // Cleanup on unmount
    return () => {
      stopCamera();
    };
  }, []);

  // Tracking Loop
  useEffect(() => {
    let animationFrameId: number;
    let detector: any = null;

    if (isTracking && isEyewear && 'FaceDetector' in window) {
      // @ts-ignore
      detector = new window.FaceDetector({ fastMode: true, maxFaces: 1 });
    }

    const detect = async () => {
      if (!videoRef.current || !isTracking) return;

      if (detector && videoRef.current.readyState === 4) {
        try {
          const faces = await detector.detect(videoRef.current);
          if (faces.length > 0) {
            const face = faces[0].boundingBox;
            // Map detected coordinates to the container view
            // Note: video is flipped scale-x-[-1], so we adjust X
            setFaceData({
              x: face.x + face.width / 2,
              y: face.y + face.height / 2,
              width: face.width,
              height: face.height,
              angle: 0 // Simplistic angle for now
            });
          }
        } catch (e) {
          console.error("Detection error", e);
        }
      }
      animationFrameId = requestAnimationFrame(detect);
    };

    if (isEyewear) detect();
    return () => cancelAnimationFrame(animationFrameId);
  }, [isTracking, isEyewear]);

  // Derived style for the product
  const getProductStyle = () => {
    if (isEyewear && faceData.width > 0) {
      // Dynamic positioning based on face detection
      const videoWidth = videoRef.current?.videoWidth || 1280;
      const videoHeight = videoRef.current?.videoHeight || 720;

      // Calculate relative percentages
      const left = (faceData.x / videoWidth) * 100;
      const top = (faceData.y / videoHeight) * 100;
      const width = (faceData.width / videoWidth) * 100 * 1.2 * manualScale; // Slightly wider than face

      return {
        position: 'absolute' as const,
        left: `${100 - left}%`, // Mirror the X position
        top: `${top - 5}%`, // Offset slightly up for eyes
        width: `${width}%`,
        transform: 'translate(-50%, -50%)',
        transition: 'all 0.1s ease-out', // Smooth "following" effect
        pointerEvents: 'none' as const,
        zIndex: 50
      };
    }

    // Default Fallback (Centered with manual controls)
    return {
      position: 'absolute' as const,
      left: '50%',
      top: isEyewear ? '45%' : '70%',
      width: isEyewear ? '30%' : '20%',
      transform: `translate(-50%, -50%) scale(${manualScale})`,
      pointerEvents: 'none' as const,
      zIndex: 50
    };
  };

  return (
    <div className="fixed inset-0 z-[100] bg-black flex flex-col items-center justify-center overflow-hidden">
      {/* Container */}
      <div className="relative w-full h-full max-w-5xl md:h-[80vh] bg-slate-900 md:rounded-3xl overflow-hidden shadow-[0_0_50px_rgba(14,165,233,0.3)] border-4 border-slate-800">

        {/* Camera Feed */}
        <video 
          ref={videoRef} 
          autoPlay 
          playsInline 
          className="w-full h-full object-cover scale-x-[-1]"
        />

        {/* Dynamic Product Overlay */}
        {isReady && (
          <img 
            src={productImage} 
            style={getProductStyle()}
            className="drop-shadow-[0_10px_20px_rgba(0,0,0,0.5)] mix-blend-multiply"
            alt="Virtual Product"
          />
        )}

        {/* AR Scan Line */}
        <div className="absolute inset-0 pointer-events-none">
           <div className="w-full h-[1px] bg-sky-400/50 shadow-[0_0_15px_rgba(14,165,233,0.8)] absolute top-0 animate-[scan_4s_ease-in-out_infinite]" />
        </div>

        {/* Header UI */}
        <div className="absolute top-0 inset-x-0 p-6 flex justify-between items-start bg-gradient-to-b from-black/80 to-transparent">
          <div className="flex items-center gap-4">
            <div className="p-3 bg-sky-500 rounded-2xl shadow-lg shadow-sky-500/20">
              <Camera className="text-white" size={24} />
            </div>
            <div>
              <h2 className="text-white font-bold text-lg tracking-tight">Virtual Mirror</h2>
              <div className="flex items-center gap-2">
                <span className="w-2 h-2 bg-green-500 rounded-full animate-pulse" />
                <span className="text-sky-300 text-xs font-medium uppercase tracking-widest">
                  {isEyewear ? 'Face Tracking Active' : 'Wrist Alignment Mode'}
                </span>
              </div>
            </div>
          </div>

          <button 
            onClick={handleClose}
            className="p-3 bg-white/10 hover:bg-white/20 text-white rounded-2xl backdrop-blur-xl transition-all border border-white/10"
          >
            <X size={28} />
          </button>
        </div>

        {/* Calibration & Status */}
        {isReady && isEyewear && faceData.width === 0 && (
          <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
            <div className="border-2 border-dashed border-sky-400/50 rounded-full w-64 h-80 animate-pulse flex items-center justify-center">
              <span className="text-sky-400 text-sm font-bold bg-black/40 px-4 py-2 rounded-full backdrop-blur-md">
