import React, { useEffect, useRef,状态, useState } from 'react';
import { Camera, X, RotateCcw, Scan, ShieldCheck, BoxSelect, User } from 'lucide-react';

interface Props {
  productImage: string;
  category: string;
  onClose: () => void;
}

const VirtualTryOn: React.FC<Props> = ({ productImage, category, onClose }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const [stream, setStream] = useState<MediaStream | null>(null);
  const [isReady, setIsReady] = useState(false);
  const [manualScale, setManualScale] = useState(1);

  // Advanced Tracking State
  const [transform, setTransform] = useState({
    x: 0,
    y: 0,
    rotateY: 0,
    rotateX: 0,
    scale: 1,
    opacity: 0
  });

  const isEyewear = category.toLowerCase().includes('eyewear') || category.toLowerCase().includes('glasses') || category.toLowerCase().includes('goggles');
  const isWatch = category.toLowerCase().includes('watch');

  // Hard-stop camera tracks to release hardware
  const stopCamera = () => {
    if (stream) {
      stream.getTracks().forEach(track => {
        track.stop();
        track.enabled = false;
      });
      setStream(null);
    }
  };

  const handleClose = () => {
    stopCamera();
    onClose();
  };

  useEffect(() => {
    const startCamera = async () => {
      try {
        const mediaStream = await navigator.mediaDevices.getUserMedia({ 
          video: { 
            facingMode: 'user', 
            width: { ideal: 1280 }, 
            height: { ideal: 720 },
            frameRate: { ideal: 30 } 
          } 
        });
        setStream(mediaStream);
        if (videoRef.current) {
          videoRef.current.srcObject = mediaStream;
          videoRef.current.onloadedmetadata = () => {
            setIsReady(true);
            // Initial transition
            setTimeout(() => {
              setTransform(prev => ({ ...prev, opacity: 1 }));
            }, 500);
          };
        }
      } catch (err) {
        console.error("Camera access denied:", err);
        alert("Camera permission is required for Virtual Try-On.");
        onClose();
      }
    };

    startCamera();
    return () => stopCamera();
  }, []);

  // Professional Tracking Loop (Experimental FaceDetector with 3D Fallback)
  useEffect(() => {
    let animationFrameId: number;
    let detector: any = null;

    if (isReady && 'FaceDetector' in window) {
      // @ts-ignore
      detector = new window.FaceDetector({ fastMode: true, maxFaces: 1 });
    }

    const processFrame = async () => {
      if (!videoRef.current || !isReady) return;

      if (detector && videoRef.current.readyState >= 2) {
        try {
          const faces = await detector.detect(videoRef.current);
          if (faces.length > 0) {
            const face = faces[0].boundingBox;
            const videoWidth = videoRef.current.videoWidth;
            const videoHeight = videoRef.current.videoHeight;

            // Calculate 3D Rotation based on face position relative to center
            // This creates the "worn" look as you move
            const centerX = videoWidth / 2;
            const centerY = videoHeight / 2;
            const faceCenterX = face.x + face.width / 2;
            const faceCenterY = face.y + face.height / 2;

            const diffX = (faceCenterX - centerX) / centerX; // -1 to 1
            const diffY = (faceCenterY - centerY) / centerY; // -1 to 1

            setTransform({
              x: faceCenterX,
              y: faceCenterY,
              // Rotate slightly towards the center to simulate perspective depth
              rotateY: diffX * -35, 
              rotateX: diffY * 25,
              scale: (face.width / videoWidth) * 3.5 * manualScale,
              opacity: 1
            });
          }
        } catch (e) {
          console.debug("Detector busy or unavailable", e);
        }
      }
      animationFrameId = requestAnimationFrame(processFrame);
    };

    processFrame();
    return () => cancelAnimationFrame(animationFrameId);
  }, [isReady, manualScale]);

  // CSS for the AR product to ensure it follows the head realistically
  const getDynamicStyle = (): React.CSSProperties => {
    if (!videoRef.current) return {};

    const vWidth = videoRef.current.clientWidth;
    const vHeight = videoRef.current.clientHeight;
    const rawVWidth = videoRef.current.videoWidth || 1280;
    const rawVHeight = videoRef.current.videoHeight || 720;

    // Mapping coordinates from raw video to CSS container
    const posX = (transform.x / rawVWidth) * vWidth;
    const posY = (transform.y / rawVHeight) * vHeight;

    // Mirror X because video is scale-x-[-1]
    const mirroredX = vWidth - posX;

    if (transform.x === 0) {
      // Centered fallback if tracking is lost
      return {
        position: 'absolute',
        left: '50%',
        top: isEyewear ? '45%' : '75%',
        width: isEyewear ? '28%' : '20%',
        transform: `translate(-50%, -50%) scale(${manualScale})`,
        opacity: transform.opacity,
        transition: 'opacity 0.5s ease',
        pointerEvents: 'none',
        zIndex: 50
      };
    }

    return {
      position: 'absolute',
      left: mirroredX,
      top: posY - (isEyewear ? (vHeight * 0.05) : 0), // Adjust to eyes for eyewear
      width: `${transform.scale * 100}%`,
      transform: `translate(-50%, -50%) perspective(1000px) rotateY(${transform.rotateY}deg) rotateX(${transform.rotateX}deg)`,
      opacity: transform.opacity,
      transition: 'all 0.08s cubic-bezier(0.1, 0.7, 0.1, 1)', // Snappy but smooth
      pointerEvents: 'none',
      zIndex: 50,
      filter: 'drop-shadow(0 15px 25px rgba(0,0,0,0.4))'
    };
  };

  return (
    <div className="fixed inset-0 z-[100] bg-black/95 backdrop-blur-xl flex flex-col items-center justify-center p-0 md:p-8 animate-in fade-in duration-300">
      <div className="relative w-full h-full max-w-6xl aspect-video bg-slate-900 shadow-[0_0_100px_rgba(0,0,0,0.8)] overflow-hidden border-0 md:border-8 md:rounded-[40px] border-slate-800 flex items-center justify-center">

        {/* Mirror Feed */}
        <video 
          ref={videoRef} 
          autoPlay 
          playsInline 
          className="w-full h-full object-cover scale-x-[-1] transition-opacity duration-1000"
          style={{ opacity: isReady ? 1 : 0 }}
        />

        {/* AR Product Layer */}
        {isReady && (
          <img 
            src={productImage} 
            style={getDynamicStyle()}
            className={`${isEyewear ? 'mix-blend-normal' : 'mix-blend-multiply'}`}
            alt="AR Product"
          />
        )}

        {/* HUD Elements */}
        <div className="absolute inset-0 pointer-events-none border-[1px] border-white/5">
           {/* Corner Accents */}
           <div className="absolute top-10 left-10 w-20 h-20 border-t-2 border-l-2 border-sky-500/50 rounded-tl-3xl" />
           <div className="absolute top-10 right-10 w-20 h-20 border-t-2 border-r-2 border-sky-500/50 rounded-tr-3xl" />
           <div className="absolute bottom-10 left-10 w-20 h-20 border-b-2 border-l-2 border-sky-500/50 rounded-bl-3xl" />
           <div className="absolute bottom-10 right-10 w-20 h-20 border-b-2 border-r-2 border-sky-500/50 rounded-br-3xl" />

           {/* Center Target */}
           <div className="absolute inset-0 flex items-center justify-center opacity-20">
              <div className="w-64 h-64 border-[1px] border-white rounded-full animate-ping duration-[4000ms]" />
              <div className="w-1 h-1 bg-white rounded-full" />
           </div>
        </div>

        {/* Top Control Bar */}
