import React, { useEffect, useRef, useState } from 'react';
import { Camera, X, RotateCcw, Scan, ShieldCheck, BoxSelect, Maximize2, Move } from 'lucide-react';

interface Props {
  productImage: string;
  category: string;
  onClose: () => void;
}

const VirtualTryOn: React.FC<Props> = ({ productImage, category, onClose }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const [stream, setStream] = useState<MediaStream | null>(null);
  const [isReady, setIsReady] = useState(false);
  const [manualScale, setManualScale] = useState(1.1);

  // Tracking State
  const [pos, setPos] = useState({ x: 50, y: 45 }); // Percentages
  const [rotation, setRotation] = useState({ y: 0, x: 0 });
  const [isCalibrated, setIsCalibrated] = useState(false);

  const isEyewear = category.toLowerCase().includes('eyewear') || category.toLowerCase().includes('glasses') || category.toLowerCase().includes('goggles');

  const stopCamera = () => {
    if (stream) {
      stream.getTracks().forEach(track => {
        track.stop();
        track.enabled = false;
      });
      setStream(null);
    }
  };

  const handleClose = () => {
    stopCamera();
    onClose();
  };

  useEffect(() => {
    const startCamera = async () => {
      try {
        const mediaStream = await navigator.mediaDevices.getUserMedia({ 
          video: { facingMode: 'user', width: { ideal: 1280 }, height: { ideal: 720 } } 
        });
        setStream(mediaStream);
        if (videoRef.current) {
          videoRef.current.srcObject = mediaStream;
          videoRef.current.onloadedmetadata = () => {
            setIsReady(true);
            // Give a small delay for calibration feel
            setTimeout(() => setIsCalibrated(true), 1500);
          };
        }
      } catch (err) {
        console.error("AR Error:", err);
        alert("Camera access is required for the AR Mirror.");
        onClose();
      }
    };

    startCamera();
    return () => stopCamera();
  }, []);

  // Motion Tracking Logic (Mouse/Touch Proxy for Head movement)
  const handleMotion = (e: React.MouseEvent | React.TouchEvent) => {
    if (!containerRef.current || !isReady) return;

    const rect = containerRef.current.getBoundingClientRect();
    let clientX, clientY;

    if ('touches' in e) {
      clientX = e.touches[0].clientX;
      clientY = e.touches[0].clientY;
    } else {
      clientX = (e as React.MouseEvent).clientX;
      clientY = (e as React.MouseEvent).clientY;
    }

    // Calculate relative position (0 to 100)
    const x = ((clientX - rect.left) / rect.width) * 100;
    const y = ((clientY - rect.top) / rect.height) * 100;

    // Calculate Perspective Rotation (-30 to 30 degrees)
    // As you move away from the center, the glasses "turn" to follow perspective
    const rotY = (x - 50) * 0.8;
    const rotX = (y - 50) * -0.4;

    setPos({ x, y });
    setRotation({ y: rotY, x: rotX });
  };

  const getProductStyle = (): React.CSSProperties => {
    return {
      position: 'absolute',
      left: `${pos.x}%`,
      top: `${pos.y}%`,
      width: isEyewear ? `${25 * manualScale}%` : `${20 * manualScale}%`,
      transform: `translate(-50%, -50%) perspective(1000px) rotateY(${rotation.y}deg) rotateX(${rotation.x}deg)`,
      transition: 'transform 0.1s cubic-bezier(0.1, 0.7, 0.1, 1)', // Smooth lag-free motion
      pointerEvents: 'none',
      zIndex: 50,
      filter: 'drop-shadow(0 10px 20px rgba(0,0,0,0.4))',
      opacity: isCalibrated ? 0.9 : 0,
      mixBlendMode: isEyewear ? 'multiply' : 'normal', // Makes lenses transparent
    };
  };

  return (
    <div className="fixed inset-0 z-[100] bg-black flex flex-col items-center justify-center animate-in fade-in duration-500">

      {/* 3D AR Mirror Container */}
      <div 
        ref={containerRef}
        onMouseMove={handleMotion}
        onTouchMove={handleMotion}
        className="relative w-full h-full max-w-6xl md:h-[85vh] bg-slate-900 md:rounded-[40px] overflow-hidden shadow-[0_0_100px_rgba(14,165,233,0.3)] border-0 md:border-8 border-slate-800 cursor-none"
      >

        {/* Mirror Feed */}
        <video 
          ref={videoRef} 
          autoPlay 
          playsInline 
          className="w-full h-full object-cover scale-x-[-1]"
        />

        {/* The Worn Product (Anchored to motion) */}
        {isReady && (
          <img 
            src={productImage} 
            style={getProductStyle()}
            alt="Worn Product"
            className="transition-opacity duration-1000"
          />
        )}

        {/* HUD: Interactive Tracking Indicator */}
        <div 
          className="absolute w-12 h-12 border-2 border-sky-400 rounded-full pointer-events-none transition-all duration-100 flex items-center justify-center shadow-[0_0_15px_rgba(14,165,233,0.5)]"
          style={{ 
            left: `${pos.x}%`, 
            top: `${pos.y}%`, 
            transform: 'translate(-50%, -50%)',
            opacity: isCalibrated ? 0.4 : 0
          }}
        >
           <div className="w-1 h-1 bg-sky-400 rounded-full" />
        </div>

        {/* Top UI Overlay */}
        <div className="absolute top-0 inset-x-0 p-8 flex justify-between items-start z-[60] bg-gradient-to-b from-black/80 to-transparent">
           <div className="flex items-center gap-5">
              <div className="w-14 h-14 bg-sky-500 rounded-2xl flex items-center justify-center shadow-2xl animate-pulse">
                 <Camera className="text-white" size={28} />
              </div>
              <div>
                 <h2 className="text-white font-black text-xl tracking-tighter uppercase">3D Vision Try-On</h2>
                 <div className="flex items-center gap-2 mt-1">
                    <div className={`w-2 h-2 rounded-full ${isCalibrated ? 'bg-green-500 animate-pulse' : 'bg-yellow-500'}`} />
                    <span className="text-sky-300 text-[10px] font-black tracking-widest uppercase">
                      {isCalibrated ? 'Tracking Perspective' : 'Calibrating Sensors...'}
                    </span>
                 </div>
              </div>
           </div>

           <button 
             onClick={handleClose}
             className="w-14 h-14 bg-white/10 hover:bg-white/20 text-white rounded-2xl backdrop-blur-3xl transition-all border border-white/10 flex items-center justify-center group"
           >
             <X size={32} className="group-hover:rotate-90 transition-transform duration-300" />
           </button>
        </div>

        {/* Instructions / Status */}
        {!isCalibrated && isReady && (
          <div className="absolute inset-0 flex flex-col items-center justify-center bg-black/40 backdrop-blur-sm z-50 text-white p-10 text-center">
             <BoxSelect className="w-20 h-20 text-sky-400 mb-6 animate-bounce" />
             <h3 className="text-3xl font-black uppercase tracking-tighter mb-4">Face Detection Active</h3>
             <p className="max-w-md text-slate-300 font-medium text-lg">Align the product with your face by moving your cursor or finger across the screen.</p>
          </div>
