import React, { useEffect, useRef, useState } from 'react';
import { Camera, X, RotateCcw, Scan, ShieldCheck, BoxSelect, Maximize2, UserCheck, AlertCircle } from 'lucide-react';

interface Props {
  productImage: string;
  category: string;
  onClose: () => void;
}

// Extend window for experimental FaceDetector API
declare global {
  interface Window {
    FaceDetector: any;
  }
}

const VirtualTryOn: React.FC<Props> = ({ productImage, category, onClose }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const [stream, setStream] = useState<MediaStream | null>(null);
  const [isReady, setIsReady] = useState(false);
  const [faceData, setFaceData] = useState<{ x: number, y: number, width: number, height: number } | null>(null);
  const [manualScale, setManualScale] = useState(1.0);
  const [error, setError] = useState<string | null>(null);

  const isEyewear = category.toLowerCase().includes('eyewear') || category.toLowerCase().includes('glasses') || category.toLowerCase().includes('goggles');

  const stopCamera = () => {
    if (stream) {
      stream.getTracks().forEach(track => {
        track.stop();
        console.log(`Track ${track.label} stopped`);
      });
      setStream(null);
    }
  };

  const handleClose = () => {
    stopCamera();
    onClose();
  };

  useEffect(() => {
    const startCamera = async () => {
      try {
        const mediaStream = await navigator.mediaDevices.getUserMedia({ 
          video: { facingMode: 'user', width: { ideal: 1280 }, height: { ideal: 720 } } 
        });
        setStream(mediaStream);
        if (videoRef.current) {
          videoRef.current.srcObject = mediaStream;
          videoRef.current.onloadedmetadata = () => {
            setIsReady(true);
          };
        }
      } catch (err) {
        console.error("Camera Error:", err);
        setError("Camera access is required for Face Tracking.");
      }
    };

    startCamera();
    return () => stopCamera();
  }, []);

  // Real-time Computer Vision Loop
  useEffect(() => {
    let animationFrameId: number;
    let detector: any = null;

    if (!isReady || !isEyewear) return;

    if ('FaceDetector' in window) {
      // @ts-ignore
      detector = new window.FaceDetector({ fastMode: true, maxFaces: 1 });
    } else {
      console.warn("FaceDetector API not supported in this browser.");
    }

    const detectFace = async () => {
      if (videoRef.current && detector && videoRef.current.readyState >= 2) {
        try {
          const faces = await detector.detect(videoRef.current);
          if (faces.length > 0) {
            const face = faces[0].boundingBox;
            // Normalize coordinates to percentages of the video feed
            setFaceData({
              x: face.x + face.width / 2,
              y: face.y + (face.height * 0.4), // Target eye level (approx 40% down the face)
              width: face.width,
              height: face.height
            });
          }
        } catch (e) {
          console.error("Detection Error", e);
        }
      }
      animationFrameId = requestAnimationFrame(detectFace);
    };

    detectFace();
    return () => cancelAnimationFrame(animationFrameId);
  }, [isReady, isEyewear]);

  // Dynamic CSS to "pin" the product to the detected face
  const getProductStyle = (): React.CSSProperties => {
    if (!faceData || !videoRef.current) {
      return { opacity: 0, display: 'none' };
    }

    const vWidth = videoRef.current.videoWidth;
    const vHeight = videoRef.current.videoHeight;

    // Convert face pixel coordinates to percentages
    const leftPercent = (faceData.x / vWidth) * 100;
    const topPercent = (faceData.y / vHeight) * 100;

    // Calculate size: Glasses should be roughly 100% of face width
    // We adjust based on manual scale for fine-tuning
    const widthPercent = (faceData.width / vWidth) * 100 * 1.1 * manualScale;

    return {
      position: 'absolute',
      // Flip X because video is mirrored
      left: `${100 - leftPercent}%`,
      top: `${topPercent}%`,
      width: `${widthPercent}%`,
      transform: 'translate(-50%, -50%)',
      pointerEvents: 'none',
      zIndex: 50,
      filter: 'drop-shadow(0 10px 15px rgba(0,0,0,0.3))',
      transition: 'all 0.05s linear', // Ultra-fast response
      opacity: 0.95,
      mixBlendMode: 'multiply' // Makes lenses look realistic on skin
    };
  };

  return (
    <div className="fixed inset-0 z-[100] bg-black flex flex-col items-center justify-center animate-in fade-in duration-300">

      {/* AR Viewport */}
      <div className="relative w-full h-full max-w-5xl md:h-[80vh] bg-slate-900 md:rounded-[40px] overflow-hidden shadow-[0_0_80px_rgba(14,165,233,0.4)] border-0 md:border-8 border-slate-800">

        {/* Camera Feed */}
        <video 
          ref={videoRef} 
          autoPlay 
          playsInline 
          className="w-full h-full object-cover scale-x-[-1]"
        />

        {/* Vision-Tracked Product */}
        {isReady && isEyewear && (
          <img 
            src={productImage} 
            style={getProductStyle()}
            alt="AR Eyewear"
          />
        )}

        {/* HUD Overlay */}
        <div className="absolute inset-0 pointer-events-none border-2 border-white/5">
           {/* Face Lock Indicator */}
           {faceData && (
             <div 
               className="absolute border-2 border-sky-400/50 rounded-full transition-all duration-75"
               style={{
                 left: `${100 - (faceData.x / (videoRef.current?.videoWidth || 1)) * 100}%`,
                 top: `${(faceData.y / (videoRef.current?.videoHeight || 1)) * 100}%`,
                 width: `${(faceData.width / (videoRef.current?.videoWidth || 1)) * 100}%`,
                 height: `${(faceData.height / (videoRef.current?.videoHeight || 1)) * 100}%`,
                 transform: 'translate(-50%, -50%)',
                 opacity: 0.3
               }}
             />
           )}

           {/* Scanning Animation */}
           <div className="absolute inset-0 overflow-hidden opacity-20">
              <div className="w-full h-1 bg-sky-400 shadow-[0_0_20px_#0ea5e9] absolute top-[-10%] animate-[scan_5s_linear_infinite]" />
           </div>
        </div>

        {/* Controls Overlay */}
        <div className="absolute top-0 inset-x-0 p-8 flex justify-between items-start z-[60] bg-gradient-to-b from-black/70 to-transparent">
           <div className="flex items-center gap-4">
              <div className="w-12 h-12 bg-sky-500 rounded-xl flex items-center justify-center shadow-lg animate-pulse">
                 <Camera className="text-white" size={24} />
              </div>
              <div>
                 <h2 className="text-white font-bold text-lg tracking-tight uppercase">AI Vision Mirror</h2>
                 <div className="flex items-center gap-2">
                    <div className={`w-2 h-2 rounded-full ${faceData ? 'bg-green-500 shadow-[0_0_8px_#22c55e]' : 'bg-yellow-500 animate-pulse'}`} />
                    <span className="text-sky-300 text-[10px] font-black tracking-widest uppercase">
                      {faceData ? 'Face Locked' : 'Searching for Face...'}
                    </span>
                 </div>
              </div>
           </div>

           <button 
             onClick={handleClose}
             className="w-12 h-12 bg-white/10 hover:bg-white/20 text-white rounded-xl backdrop-blur-md transition-all border border-white/10 flex items-center justify-center"
           >
             <X size={24} />
           </button>
        </div>

        {/* Footer Interaction */}
        <div className="absolute bottom-0 inset-x-0 p-8 flex flex-col md:flex-row items-center justify-between gap-6 z-[60] bg-gradient-to-t from-black/80 to-transparent">
           <div className="flex flex-col gap-2 bg-black/40 backdrop-blur-xl p-4 rounded-2xl border border-white/10 w-full md:w-auto">
              <div className="flex justify-between text-[10px] font-black text-gray-400 uppercase tracking-widest">
                 <span>Manual Fit Adjustment</span>
                 <span className="text-sky-400">{(manualScale * 100).toFixed(0)}%</span>
              </div>
              <input 
                 type="range" min="0.7" max="1.5" step="0.01" value={manualScale} 
                 onChange={(e) => setManualScale(parseFloat(e.target.value))}
                 className="w-full md:w-48 h-1.5 bg-white/20 rounded-full appearance-none cursor-pointer accent-sky-500" 
              />
           </div>

           <div className="flex items-center gap-3">
              <button 
                onClick={() => setManualScale(1.0)}
                className="px-4 py-2 bg-white/10 hover:bg-white/20 text-white rounded-lg text-xs font-bold uppercase transition-all flex items-center gap-2"
              >
                <RotateCcw size={14} /> Reset
              </button>
              <div className="px-4 py-2 bg-sky-500 text-white rounded-lg text-xs font-bold uppercase shadow-lg flex items-center gap-2">
                <UserCheck size={14} /> Live AR Tracking
              </div>
           </div>
        </div>

        {/* Loading / Error States */}
        {!isReady && !error && (
          <div className="absolute inset-0 bg-slate-900 flex flex-col items-center justify-center text-white z-[70]">
            <Scan className="w-16 h-16 text-sky-500 animate-bounce mb-4" />
            <h3 className="text-xl font-bold">Initializing AR Engine...</h3>
            <p className="text-slate-400 text-sm mt-2">Connecting to Computer Vision Service</p>
          </div>
        )}

        {error && (
          <div className="absolute inset-0 bg-slate-950 flex flex-col items-center justify-center text-white z-[70] p-10 text-center">
            <AlertCircle className="w-16 h-16 text-rose-500 mb-4" />
            <h3 className="text-xl font-bold">{error}</h3>
            <button onClick={handleClose} className="mt-6 bg-white text-black px-6 py-2 rounded-full font-bold">Return to Product</button>
          </div>
        )}
      </div>

      {/* Privacy Notice */}
      <div className="mt-6 flex items-center gap-6 opacity-40">
         <div className="flex items-center gap-2 text-white text-[10px] font-bold tracking-widest uppercase">
            <ShieldCheck size={14} className="text-green-500" /> Local Vision Processing
         </div>
         <div className="w-1 h-1 bg-white rounded-full" />
         <div className="flex items-center gap-2 text-white text-[10px] font-bold tracking-widest uppercase">
            <Maximize2 size={14} className="text-sky-500" /> Auto-Scaling AR
         </div>
      </div>

      <style>{`
        @keyframes scan {
          0% { top: -10%; }
          100% { top: 110%; }
        }
        input[type='range']::-webkit-slider-thumb {
          -webkit-appearance: none;
          appearance: none;
          width: 18px;
          height: 18px;
          background: #ffffff;
          border: 3px solid #0ea5e9;
          cursor: pointer;
          border-radius: 50%;
        }
      `}</style>
    </div>
  );
};

