import React, { useEffect, useRef, useState } from 'react';
import { Camera, X, RotateCcw, Scan, ShieldCheck, BoxSelect, Maximize2, UserCheck, AlertCircle, Loader2 } from 'lucide-react';

interface Props {
  productImage: string;
  category: string;
  onClose: () => void;
}

// Safely access MediaPipe globals from the script tag
declare global {
  interface Window {
    FaceLandmarker: any;
    FilesetResolver: any;
  }
}

const VirtualTryOn: React.FC<Props> = ({ productImage, category, onClose }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const [stream, setStream] = useState<MediaStream | null>(null);
  const [isReady, setIsReady] = useState(false);
  const [isLoadingModel, setIsLoadingModel] = useState(true);
  const [faceTransform, setFaceTransform] = useState({
    x: 0,
    y: 0,
    rotation: 0,
    scale: 0,
    visible: false
  });
  const [manualScale, setManualScale] = useState(1.0);
  const [error, setError] = useState<string | null>(null);

  const isEyewear = category.toLowerCase().includes('eyewear') || category.toLowerCase().includes('glasses') || category.toLowerCase().includes('goggles');

  const stopCamera = () => {
    if (stream) {
      stream.getTracks().forEach(track => {
        track.stop();
      });
      setStream(null);
    }
  };

  const handleClose = () => {
    stopCamera();
    onClose();
  };

  useEffect(() => {
    const startCamera = async () => {
      try {
        const mediaStream = await navigator.mediaDevices.getUserMedia({ 
          video: { facingMode: 'user', width: { ideal: 1280 }, height: { ideal: 720 } } 
        });
        setStream(mediaStream);
        if (videoRef.current) {
          videoRef.current.srcObject = mediaStream;
          videoRef.current.onloadedmetadata = () => {
            setIsReady(true);
          };
        }
      } catch (err) {
        console.error("Camera Error:", err);
        setError("Camera access is required for Face Tracking.");
      }
    };

    startCamera();
    return () => stopCamera();
  }, []);

  // Computer Vision Logic using MediaPipe
  useEffect(() => {
    let faceLandmarker: any;
    let animationFrameId: number;
    let lastVideoTime = -1;

    const setupTracking = async () => {
      // Check if MediaPipe is loaded in the window
      const checkLibrary = async (retries = 0): Promise<boolean> => {
        if (window.FaceLandmarker && window.FilesetResolver) return true;
        if (retries > 20) return false; // Fail after 10 seconds (20 * 500ms)
        await new Promise(resolve => setTimeout(resolve, 500));
        return checkLibrary(retries + 1);
      };

      const isLoaded = await checkLibrary();
      if (!isLoaded) {
        setError("Face tracking library failed to initialize. Please check your connection.");
        return;
      }

      try {
        const filesetResolver = await window.FilesetResolver.forVisionTasks(
          "https://cdn.jsdelivr.net/npm/@mediapipe/tasks-vision@0.10.3/wasm"
        );

        faceLandmarker = await window.FaceLandmarker.createFromOptions(filesetResolver, {
          baseOptions: {
            modelAssetPath: `https://storage.googleapis.com/mediapipe-models/face_landmarker/face_landmarker/float16/1/face_landmarker.task`,
            delegate: "GPU"
          },
          outputFaceBlendshapes: false,
          runningMode: "VIDEO",
          numFaces: 1
        });

        setIsLoadingModel(false);
        predict();
      } catch (e) {
        console.error("ML Init Error:", e);
        setError("Failed to initialize Computer Vision model.");
      }
    };

    const predict = () => {
      if (!videoRef.current || !faceLandmarker) return;

      const startTimeMs = performance.now();
      if (lastVideoTime !== videoRef.current.currentTime) {
        lastVideoTime = videoRef.current.currentTime;
        const results = faceLandmarker.detectForVideo(videoRef.current, startTimeMs);

        if (results.faceLandmarks && results.faceLandmarks.length > 0) {
          const landmarks = results.faceLandmarks[0];

          // MediaPipe Landmarks:
          // 168: Bridge of nose
          // 33: Left eye inner
          // 263: Right eye inner
          // 127: Left temple
          // 356: Right temple

          const bridge = landmarks[168];
          const leftEye = landmarks[33];
          const rightEye = landmarks[263];
          const leftTemple = landmarks[127];
          const rightTemple = landmarks[356];

          // Calculate Roll Rotation
          const dy = rightEye.y - leftEye.y;
          const dx = rightEye.x - leftEye.x;
          const angle = Math.atan2(dy, dx) * (180 / Math.PI);

          // Calculate Scale (Distance between temples)
          const dist = Math.sqrt(
            Math.pow(rightTemple.x - leftTemple.x, 2) + 
            Math.pow(rightTemple.y - leftTemple.y, 2)
          );

          setFaceTransform({
            x: bridge.x,
            y: bridge.y,
            rotation: angle,
            scale: dist,
            visible: true
          });
        } else {
          setFaceTransform(prev => ({ ...prev, visible: false }));
        }
      }
      animationFrameId = requestAnimationFrame(predict);
    };

    if (isReady) setupTracking();

    return () => {
      if (animationFrameId) cancelAnimationFrame(animationFrameId);
      if (faceLandmarker) faceLandmarker.close();
    };
  }, [isReady]);

  const getProductStyle = (): React.CSSProperties => {
    if (!faceTransform.visible || !videoRef.current) {
      return { opacity: 0, transition: 'opacity 0.3s' };
    }

    const left = (1 - faceTransform.x) * 100; // Inverted for mirrored view
    const top = faceTransform.y * 100;

    // Scale factor adjusted for visual fit
    const baseWidth = 135; 
    const calculatedWidth = faceTransform.scale * baseWidth * manualScale;

    return {
      position: 'absolute',
      left: `${left}%`,
      top: `${top}%`,
      width: `${calculatedWidth}%`,
      transform: `translate(-50%, -50%) rotate(${faceTransform.rotation}deg)`,
      pointerEvents: 'none',
      zIndex: 50,
      filter: 'drop-shadow(0 15px 30px rgba(0,0,0,0.4))',
      opacity: 0.98,
      mixBlendMode: isEyewear ? 'multiply' : 'normal'
    };
  };

  return (
    <div className="fixed inset-0 z-[100] bg-black flex flex-col items-center justify-center animate-in fade-in duration-300">

      {/* AR Viewport */}
      <div className="relative w-full h-full max-w-6xl md:h-[85vh] bg-slate-900 md:rounded-[40px] overflow-hidden shadow-[0_0_100px_rgba(14,165,233,0.3)] border-0 md:border-8 border-slate-800">

        {/* Camera Feed */}
        <video 
          ref={videoRef} 
          autoPlay 
          playsInline 
          className="w-full h-full object-cover scale-x-[-1]"
        />

        {/* Vision-Tracked Product */}
        {isReady && !isLoadingModel && (
          <img 
            src={productImage} 
            style={getProductStyle()}
            alt="AR Product"
            className="transition-[width,transform] duration-[40ms] ease-linear"
          />
        )}

        {/* HUD: Scanning Overlays */}
        {(isLoadingModel || !faceTransform.visible) && !error && (
          <div className="absolute inset-0 bg-black/40 backdrop-blur-sm flex flex-col items-center justify-center text-white z-50 text-center px-10">
             {isLoadingModel ? (
               <>
                 <Loader2 className="w-16 h-16 text-sky-500 animate-spin mb-6" />
                 <h3 className="text-2xl font-black uppercase tracking-widest">Waking AI Engine</h3>
                 <p className="text-slate-400 mt-2">Connecting to Computer Vision Mesh...</p>
               </>
             ) : (
               <>
                 <Scan className="w-16 h-16 text-sky-400 mb-6 animate-pulse" />
                 <h3 className="text-2xl font-black uppercase tracking-widest">Face Required</h3>
                 <p className="text-slate-400 mt-2">Center your face in the mirror to begin.</p>
               </>
             )}
          </div>
        )}

        {/* Corner Brackets */}
        <div className="absolute inset-0 pointer-events-none p-10">
           <div className="w-full h-full relative">
              <div className="absolute top-0 left-0 w-8 h-8 border-t-4 border-l-4 border-sky-500/30 rounded-tl-xl" />
              <div className="absolute top-0 right-0 w-8 h-8 border-t-4 border-r-4 border-sky-500/30 rounded-tr-xl" />
              <div className="absolute bottom-0 left-0 w-8 h-8 border-b-4 border-l-4 border-sky-500/30 rounded-bl-xl" />
              <div className="absolute bottom-0 right-0 w-8 h-8 border-b-4 border-r-4 border-sky-500/30 rounded-br-xl" />
           </div>
        </div>

        {/* Header Controls */}
        <div className="absolute top-0 inset-x-0 p-8 flex justify-between items-start z-[60] bg-gradient-to-b from-black/80 to-transparent">
           <div className="flex items-center gap-4">
              <div className="w-12 h-12 bg-sky-500 rounded-2xl flex items-center justify-center shadow-lg">
                 <Camera className="text-white" size={24} />
              </div>
              <div className="hidden sm:block">
                 <h2 className="text-white font-black text-lg tracking-tight uppercase">Vision Mirror Pro</h2>
                 <div className="flex items-center gap-2">
                    <div className={`w-2 h-2 rounded-full ${faceTransform.visible ? 'bg-green-500 animate-pulse' : 'bg-red-500'}`} />
                    <span className="text-sky-300 text-[10px] font-black tracking-widest uppercase">
                      {faceTransform.visible ? 'Mesh Locked' : 'Searching...'}
                    </span>
                 </div>
              </div>
           </div>

           <button 
             onClick={handleClose}
             className="w-12 h-12 bg-white/10 hover:bg-white/20 text-white rounded-2xl backdrop-blur-md transition-all border border-white/10 flex items-center justify-center"
           >
             <X size={24} />
           </button>
        </div>

        {/* Bottom Calibration */}
        <div className="absolute bottom-0 inset-x-0 p-8 flex flex-col md:flex-row items-center justify-between gap-6 z-[60] bg-gradient-to-t from-black/90 to-transparent">
           <div className="flex flex-col gap-2 bg-black/60 backdrop-blur-2xl p-4 rounded-3xl border border-white/10 w-full md:w-auto">
              <div className="flex justify-between text-[10px] font-black text-gray-400 uppercase tracking-widest">
                 <span>Manual Correction</span>
                 <span className="text-sky-400">{(manualScale * 100).toFixed(0)}%</span>
              </div>
              <input 
                 type="range" min="0.5" max="1.8" step="0.01" value={manualScale} 
                 onChange={(e) => setManualScale(parseFloat(e.target.value))}
                 className="w-full md:w-56 h-1.5 bg-white/20 rounded-full appearance-none cursor-pointer accent-sky-500" 
              />
           </div>

           <div className="flex items-center gap-3">
              <button 
                onClick={() => setManualScale(1.0)}
                className="px-6 py-3 bg-white/10 hover:bg-white/20 text-white rounded-2xl text-xs font-bold uppercase tracking-widest transition-all"
              >
                Reset
              </button>
              <div className="px-6 py-3 bg-sky-500 text-white rounded-2xl text-xs font-bold uppercase tracking-widest shadow-xl flex items-center gap-2">
                <UserCheck size={16} /> Real-time AR
              </div>
           </div>
        </div>

        {error && (
          <div className="absolute inset-0 bg-slate-950 flex flex-col items-center justify-center text-white z-[70] p-12 text-center">
            <AlertCircle className="w-16 h-16 text-rose-500 mb-6" />
            <h3 className="text-2xl font-black uppercase">{error}</h3>
            <button onClick={handleClose} className="mt-8 bg-sky-500 text-white px-8 py-3 rounded-full font-bold uppercase tracking-widest">
              Back to Catalog
            </button>
          </div>
        )}
      </div>

      <style>{`
        input[type='range']::-webkit-slider-thumb {
          -webkit-appearance: none;
          appearance: none;
          width: 22px;
          height: 22px;
          background: #ffffff;
          border: 4px solid #0ea5e9;
          cursor: pointer;
          border-radius: 50%;
          box-shadow: 0 0 10px rgba(14,165,233,0.4);
        }
      `}</style>
    </div>
  );
};

